function solve(words: string[]): number[] {
    const n = words.length;
    if (n <= 1) {
        return new Array(n).fill(0);
    }

    // Compute prefix array
    const prefix: number[] = new Array(n - 1);
    for (let i = 0; i < n - 1; i++) {
        prefix[i] = commonPrefixLength(words[i], words[i + 1]);
    }

    // Compute prefix_max array
    const prefixMax: number[] = new Array(n - 1);
    prefixMax[0] = prefix[0];
    for (let i = 1; i < n - 1; i++) {
        prefixMax[i] = Math.max(prefixMax[i - 1], prefix[i]);
    }

    // Compute suffix_max array
    const suffixMax: number[] = new Array(n - 1);
    suffixMax[n - 2] = prefix[n - 2];
    for (let i = n - 3; i >= 0; i--) {
        suffixMax[i] = Math.max(prefix[i], suffixMax[i + 1]);
    }

    const answer: number[] = new Array(n).fill(0);

    for (let i = 0; i < n; i++) {
        if (n - 1 < 2) {
            answer[i] = 0;
            continue;
        }

        let leftPart = 0;
        if (i - 2 >= 0) {
            leftPart = prefixMax[i - 2];
        }

        let rightPart = 0;
        if (i + 1 <= n - 2) {
            rightPart = suffixMax[i + 1];
        }

        let newPair = 0;
        if (i > 0 && i < n - 1) {
            newPair = commonPrefixLength(words[i - 1], words[i + 1]);
        }

        answer[i] = Math.max(leftPart, rightPart, newPair);
    }

    return answer;
}

function commonPrefixLength(s1: string, s2: string): number {
    const minLen = Math.min(s1.length, s2.length);
    for (let i = 0; i < minLen; i++) {
        if (s1[i] !== s2[i]) {
            return i;
        }
    }
    return minLen;
}

